package main

import (
	"fmt"

	lodash "github.com/malcolmston/lodash"
)

func main() {
	nums := []int{1, 2, 3, 4, 5, 6}
	evens := lodash.Filter(nums, func(n int) bool { return n%2 == 0 })
	doubled := lodash.Map(evens, func(n int) int { return n * 2 })
	total := lodash.Sum(doubled)
	fmt.Println(evens)
	fmt.Println(doubled)
	fmt.Println(total)
}

